    fp s3_sl   = (KmCai*powf(Nao,3.0f)*(1.0f+powf(initvalu_33/KmNai,3.0f))+powf(KmNao,3.0f)*initvalu_37+powf(KmNai,3.0f)*Cao*(1.0f+initvalu_37/KmCai)+KmCao*powf(initvalu_33,3.0f)+powf(initvalu_33,3.0f)*Cao+powf(Nao,3.0f)*initvalu_37)*(1.0f+ksat*expf((nu-1.0f)*initvalu_39*FoRT));
    fp I_ncx_junc = Fjunc*IbarNCX*powf(Q10NCX,Qpow)*Ka_junc*(s1_junc-s2_junc)/s3_junc;
    fp I_ncx_sl   = Fsl*IbarNCX*powf(Q10NCX,Qpow)*Ka_sl*(s1_sl-s2_sl)/s3_sl;
    fp I_ncx      = I_ncx_junc+I_ncx_sl;
    finavalu[offset_45] = 2.0f*I_ncx*Cmem/(Vmyo*2.0f*Frdy)*1e3f;

    // I_pca
    fp I_pca_junc = Fjunc*powf(Q10SLCaP,Qpow)*IbarSLCaP*powf(initvalu_36,1.6f)/(powf(KmPCa,1.6f)+powf(initvalu_36,1.6f));
    fp I_pca_sl   = Fsl*powf(Q10SLCaP,Qpow)*IbarSLCaP*powf(initvalu_37,1.6f)/(powf(KmPCa,1.6f)+powf(initvalu_37,1.6f));
    fp I_pca      = I_pca_junc+I_pca_sl;
    finavalu[offset_44] = -I_pca*Cmem/(Vmyo*2.0f*Frdy)*1e3f;

    // I_cabk
    fp I_cabk_junc = Fjunc*GCaB*(initvalu_39-eca_junc);
    fp I_cabk_sl   = Fsl*GCaB*(initvalu_39-eca_sl);
    fp I_cabk      = I_cabk_junc+I_cabk_sl;
    finavalu[offset_46] = -I_cabk*Cmem/(Vmyo*2.0f*Frdy)*1e3f;

    // SR fluxes
    fp MaxSR  = 15.0f;
    fp MinSR  = 1.0f;
    fp kCaSR  = MaxSR-(MaxSR-MinSR)/(1.0f+powf(ec50SR/initvalu_31,2.5f));
    fp koSRCa = koCa/kCaSR;
    fp kiSRCa = kiCa*kCaSR;
    fp RI     = 1.0f-initvalu_14-initvalu_15-initvalu_16;
    finavalu[offset_14] = (kim*RI-kiSRCa*initvalu_36*initvalu_14)-(koSRCa*powf(initvalu_36,2.0f)*initvalu_14-kom*initvalu_15);
    finavalu[offset_15] = (koSRCa*powf(initvalu_36,2.0f)*initvalu_14-kom*initvalu_15)-(kiSRCa*initvalu_36*initvalu_15-kim*initvalu_16);
    finavalu[offset_16] = (kiSRCa*initvalu_36*initvalu_15-kim*initvalu_16)-(kom*initvalu_16-koSRCa*powf(initvalu_36,2.0f)*RI);
    fp J_SRCarel = ks*initvalu_15*(initvalu_31-initvalu_36);
    fp J_serca   = powf(Q10SRCaP,Qpow)*Vmax_SRCaP*(powf(initvalu_38/Kmf,hillSRCaP)-powf(initvalu_31/Kmr,hillSRCaP))/(1.0f+powf(initvalu_38/Kmf,hillSRCaP)+powf(initvalu_31/Kmr,hillSRCaP));
    fp J_SRleak  = 5.348e-6f*(initvalu_31-initvalu_36);

    // Buffering
    finavalu[offset_17] = kon_na*initvalu_32*(Bmax_Naj-initvalu_17)-koff_na*initvalu_17;
    finavalu[offset_18] = kon_na*initvalu_33*(Bmax_Nasl-initvalu_18)-koff_na*initvalu_18;

    finavalu[offset_19] = kon_tncl*initvalu_38*(Bmax_TnClow-initvalu_19)-koff_tncl*initvalu_19;
    finavalu[offset_20] = kon_tnchca*initvalu_38*(Bmax_TnChigh-initvalu_20-initvalu_21)-koff_tnchca*initvalu_20;
    finavalu[offset_21] = kon_tnchmg*Mgi*(Bmax_TnChigh-initvalu_20-initvalu_21)-koff_tnchmg*initvalu_21;
    finavalu[offset_22] = 0.0f;
    finavalu[offset_23] = kon_myoca*initvalu_38*(Bmax_myosin-initvalu_23-initvalu_24)-koff_myoca*initvalu_23;
    finavalu[offset_24] = kon_myomg*Mgi*(Bmax_myosin-initvalu_23-initvalu_24)-koff_myomg*initvalu_24;
    finavalu[offset_25] = kon_sr*initvalu_38*(Bmax_SR-initvalu_25)-koff_sr*initvalu_25;
    fp J_CaB_cytosol = finavalu[offset_19]+finavalu[offset_20]+finavalu[offset_21]+finavalu[offset_22]+finavalu[offset_23]+finavalu[offset_24]+finavalu[offset_25];

    finavalu[offset_26] = kon_sll*initvalu_36*(Bmax_SLlowj-initvalu_26)-koff_sll*initvalu_26;
    finavalu[offset_27] = kon_sll*initvalu_37*(Bmax_SLlowsl-initvalu_27)-koff_sll*initvalu_27;
    finavalu[offset_28] = kon_slh*initvalu_36*(Bmax_SLhighj-initvalu_28)-koff_slh*initvalu_28;
    finavalu[offset_29] = kon_slh*initvalu_37*(Bmax_SLhighsl-initvalu_29)-koff_slh*initvalu_29;
    fp J_CaB_junction = finavalu[offset_26]+finavalu[offset_28];
    fp J_CaB_sl       = finavalu[offset_27]+finavalu[offset_29];

    finavalu[offset_30] = kon_csqn*initvalu_31*(Bmax_Csqn-initvalu_30)-koff_csqn*initvalu_30;
    fp oneovervsr = 1.0f/Vsr;
    finavalu[offset_31] = J_serca*Vmyo*oneovervsr-(J_SRleak*Vmyo*oneovervsr+J_SRCarel)-finavalu[offset_30];

    fp I_Na_tot_junc = I_Na_junc+I_nabk_junc+3.0f*I_ncx_junc+3.0f*I_nak_junc+I_CaNa_junc;
    fp I_Na_tot_sl   = I_Na_sl+I_nabk_sl+3.0f*I_ncx_sl+3.0f*I_nak_sl+I_CaNa_sl;
    finavalu[offset_32] = -I_Na_tot_junc*Cmem/(Vjunc*Frdy)+J_na_juncsl/Vjunc*(initvalu_33-initvalu_32)-finavalu[offset_17];
    fp oneovervsl = 1.0f/Vsl;
    finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(initvalu_32-initvalu_33)+J_na_slmyo*oneovervsl*(initvalu_34-initvalu_33)-finavalu[offset_18];
    finavalu[offset_34] = J_na_slmyo/Vmyo*(initvalu_33-initvalu_34);

    fp I_K_tot = I_to+I_kr+I_ks+I_ki-2.0f*I_nak+I_CaK+I_kp;
    finavalu[offset_35] = 0.0f;

    fp I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2.0f*I_ncx_junc;
    fp I_Ca_tot_sl   = I_Ca_sl+I_cabk_sl+I_pca_sl-2.0f*I_ncx_sl;
    finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2.0f*Frdy)+J_ca_juncsl/Vjunc*(initvalu_37-initvalu_36)-J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;
    finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2.0f*Frdy)+J_ca_juncsl/Vsl*(initvalu_36-initvalu_37)+J_ca_slmyo/Vsl*(initvalu_38-initvalu_37)-J_CaB_sl;
    finavalu[offset_38] = -J_serca-J_CaB_cytosol+J_ca_slmyo/Vmyo*(initvalu_37-initvalu_38);

    // Simulation type
    fp I_app;
    int state = 1;
    if(state==0){
        I_app = 0.0f;
    } else if(state==1){
        if(fmodf(timeinst,parameter_1) <= 5.0f){
            I_app = 9.5f;
        } else {
            I_app = 0.0f;
        }
    } else {
        fp V_hold = -55.0f;
        fp V_test = 0.0f;
        fp V_clamp;
        if(timeinst>0.5f && timeinst<200.5f){
            V_clamp = V_test;
        } else {
            V_clamp = V_hold;
        }
        fp R_clamp = 0.04f;
        I_app = (V_clamp-initvalu_39)/R_clamp;
    }

    fp I_Na_tot  = I_Na_tot_junc+I_Na_tot_sl;
    fp I_Cl_tot  = I_ClCa+I_Clbk;
    fp I_Ca_tot2 = I_Ca_tot_junc+I_Ca_tot_sl;
    fp I_tot     = I_Na_tot+I_Cl_tot+I_Ca_tot2+I_K_tot;
    finavalu[offset_39] = -(I_tot-I_app);

    finavalu[offset_41] = 0.0f;
    finavalu[offset_42] = 0.0f;
}

